    # ── CODE EXAMPLES: Sorting ────────────────────────────────────────────
    {"intent_id": "code_sort_python", "query": "write a sorting algorithm in python", "response": "```python\n# Quick sort\ndef quicksort(arr: list) -> list:\n    if len(arr) <= 1:\n        return arr\n    pivot = arr[len(arr) // 2]\n    left = [x for x in arr if x < pivot]\n    middle = [x for x in arr if x == pivot]\n    right = [x for x in arr if x > pivot]\n    return quicksort(left) + middle + quicksort(right)\n\nprint(quicksort([3, 6, 8, 10, 1, 2, 1]))\n# [1, 1, 2, 3, 6, 8, 10]\n\n# Or just use built-in:\nsorted([3, 1, 2])           # [1, 2, 3]\n[3, 1, 2].sort()            # in-place\nsorted(items, key=len)      # sort by length\n```", "variant": "short"},
    {"intent_id": "code_sort_javascript", "query": "write a sorting algorithm in javascript", "response": "```javascript\n// Quick sort\nfunction quickSort(arr) {\n  if (arr.length <= 1) return arr;\n  const pivot = arr[Math.floor(arr.length / 2)];\n  const left = arr.filter(x => x < pivot);\n  const middle = arr.filter(x => x === pivot);\n  const right = arr.filter(x => x > pivot);\n  return [...quickSort(left), ...middle, ...quickSort(right)];\n}\n\nconsole.log(quickSort([3, 6, 8, 10, 1, 2, 1]));\n\n// Built-in (sorts in-place, lexicographic by default!):\n[3, 1, 2].sort((a, b) => a - b);  // numeric sort\n```", "variant": "short"},

