    # ── CODE EXAMPLES: Data Structures ────────────────────────────────────
    {"intent_id": "code_linked_list_python", "query": "write a linked list in python", "response": "```python\nclass Node:\n    def __init__(self, val, next=None):\n        self.val = val\n        self.next = next\n\nclass LinkedList:\n    def __init__(self):\n        self.head = None\n\n    def push(self, val):\n        self.head = Node(val, self.head)\n\n    def pop(self):\n        if not self.head: return None\n        val = self.head.val\n        self.head = self.head.next\n        return val\n\n    def __iter__(self):\n        node = self.head\n        while node:\n            yield node.val\n            node = node.next\n\nll = LinkedList()\nfor x in [3, 2, 1]: ll.push(x)\nprint(list(ll))  # [1, 2, 3]\n```", "variant": "short"},
    {"intent_id": "code_stack_python", "query": "write a stack in python", "response": "```python\nclass Stack:\n    def __init__(self):\n        self._items = []\n\n    def push(self, item):\n        self._items.append(item)\n\n    def pop(self):\n        if self.is_empty(): raise IndexError(\"Stack is empty\")\n        return self._items.pop()\n\n    def peek(self):\n        if self.is_empty(): raise IndexError(\"Stack is empty\")\n        return self._items[-1]\n\n    def is_empty(self) -> bool:\n        return len(self._items) == 0\n\n    def __len__(self) -> int:\n        return len(self._items)\n\nstack = Stack()\nstack.push(1); stack.push(2); stack.push(3)\nprint(stack.pop())  # 3\n```", "variant": "short"},
    {"intent_id": "code_binary_search_python", "query": "write binary search in python", "response": "```python\ndef binary_search(arr: list, target: int) -> int:\n    left, right = 0, len(arr) - 1\n    while left <= right:\n        mid = (left + right) // 2\n        if arr[mid] == target:\n            return mid\n        elif arr[mid] < target:\n            left = mid + 1\n        else:\n            right = mid - 1\n    return -1  # not found\n\nnums = [1, 3, 5, 7, 9, 11]\nprint(binary_search(nums, 7))   # 3\nprint(binary_search(nums, 4))   # -1\n```", "variant": "short"},

